fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let max_index = n - 1;
    let mut sieve = vec![true; max_index + 1];
    sieve[0] = false;
    sieve[1] = false;
    let sqrt_max = (max_index as f64).sqrt() as u64;
    for i in 2..=sqrt_max {
        if sieve[i] {
            for j in (i * i)..=max_index {
                sieve[j] = false;
            }
        }
    }
    let mut sum_a = 0;
    let mut sum_b = 0;
    for (i, &num) in nums.iter().enumerate() {
        if sieve[i] {
            sum_a += num;
        } else {
            sum_b += num;
        }
    }
    (sum_a - sum_b).abs()
}
```
